// ApplyOAuthApplication creates or updates a OAuthApplication by id or name.
func (c *Client) ApplyOAuthApplication(ctx context.Context, params ApplyOAuthApplicationParams, opts ...RequestOption) (*ApplyResult, error) {
	scope := strings.TrimSpace(params.Organization)
	if scope == "" {
		return nil, fmt.Errorf("organization is required")
	}
	name := strings.TrimSpace(params.Name)
	if name == "" {
		return nil, fmt.Errorf("name is required")
	}
	existingID, err := c.findOAuthApplication(ctx, scope, params.ID, name, params.Provider, opts...)
	if err != nil {
		return nil, err
	}
	if existingID == "" {
		createParams := CreateOrganizationOAuthApplicationParams{
			OrganizationDomain:      scope,
			ClientID:                params.ClientID,
			ClientSecret:            params.ClientSecret,
			GitHub:                  params.GitHub,
			Google:                  params.Google,
			GrantTypes:              params.GrantTypes,
			Name:                    params.Name,
			Provider:                params.Provider,
			ProviderConfig:          params.ProviderConfig,
			RedirectURIs:            params.RedirectURIs,
			ResponseTypes:           params.ResponseTypes,
			Scopes:                  params.Scopes,
			Status:                  params.Status,
			TokenEndpointAuthMethod: params.TokenEndpointAuthMethod,
		}
		resp, err := c.CreateOrganizationOAuthApplication(ctx, createParams, opts...)
		if err != nil {
			return &ApplyResult{Type: "OAuthApplication", Name: name, Operation: "created", Response: resp}, err
		}
		return &ApplyResult{Type: "OAuthApplication", Name: name, Operation: "created", Response: resp}, nil
	}
	updateParams := UpdateOrganizationOAuthApplicationParams{
		OrganizationDomain:      scope,
		OAuthApplicationID:      existingID,
		ClientID:                optionalApplyString(params.ClientID),
		ClientSecret:            params.ClientSecret,
		GitHub:                  params.GitHub,
		Google:                  params.Google,
		GrantTypes:              params.GrantTypes,
		Name:                    optionalApplyString(params.Name),
		Provider:                optionalApplyString(params.Provider),
		ProviderConfig:          params.ProviderConfig,
		RedirectURIs:            params.RedirectURIs,
		ResponseTypes:           params.ResponseTypes,
		Scopes:                  params.Scopes,
		Status:                  params.Status,
		TokenEndpointAuthMethod: params.TokenEndpointAuthMethod,
	}
	resp, err := c.UpdateOrganizationOAuthApplication(ctx, updateParams, opts...)
	if err != nil {
		return &ApplyResult{Type: "OAuthApplication", Name: name, ID: existingID, Operation: "configured", Response: resp}, err
	}
	return &ApplyResult{Type: "OAuthApplication", Name: name, ID: existingID, Operation: "configured", Response: resp}, nil
}

