func (c *Client) findOAuthApplication(ctx context.Context, scope, id, name string, match string, opts ...RequestOption) (string, error) {
	if id != "" {
		resp, err := c.GetOrganizationOAuthApplication(ctx, GetOrganizationOAuthApplicationParams{OrganizationDomain: scope, OAuthApplicationID: id}, opts...)
		if err == nil {
			return id, nil
		}
		if resp == nil || resp.StatusCode != http.StatusNotFound {
			return "", err
		}
	}
	resp, err := c.ListOrganizationOAuthApplications(ctx, ListOrganizationOAuthApplicationsParams{OrganizationDomain: scope}, opts...)
	if err != nil {
		return "", err
	}
	var list oAuthApplicationApplyList
	if err := resp.DecodeJSON(&list); err != nil {
		return "", err
	}
	var matches []string
	for _, item := range list.Items {
		if item.Name != name {
			continue
		}
		if match != "" && item.Provider != match {
			continue
		}
		matches = append(matches, item.ID)
	}
	if len(matches) > 1 {
		return "", fmt.Errorf("multiple OAuthApplication resources match name %q; set id", name)
	}
	if len(matches) == 1 {
		return matches[0], nil
	}
	return "", nil
}

